var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"대장, 마지막 외벽 청소도 끝났어요.","JPN":"隊長、最後の外壁まで掃除終わりました。","ENG":"Commander, the last round of outer wall cleanup is done.","TWN":"隊長，最後一次外牆清理也結束了。"},"stage":{"bg":"COUNTERSIDE_AURORA_01","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"다들 고생했다. 하담이가 나전 천갑의 정비를 마칠 동안 대기하거라.","JPN":"皆ご苦労だった。カタンが螺鈿天甲の整備を終えるまで待機するように。","ENG":"Good work, everyone. While Ha Dam finishes tuning the Heavenly Inlaid Armor, wait here.","TWN":"大家辛苦了。等夏垣維修完螺鈿天甲，你們就待命吧。"},"stage":{"bg":"COUNTERSIDE_AURORA_01","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MEMBER1_NPC_SAMGUN_NULL","text":{"KOREA":"저기. 막동 오라버니.","JPN":"ねえ、ドウヤ兄様。","ENG":"Hey, Makdong?","TWN":"那個，莫冬哥哥。"},"stage":{"bg":"COUNTERSIDE_AURORA_01","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MEMBER1_NPC_SAMGUN_NULL","text":{"KOREA":"우리가 관리하는 나전 천갑이라는 건, 정확히 뭐하는 거야?","JPN":"私たちが管理してる螺鈿天甲って、具体的に何なの？","ENG":"What exactly is this Heavenly Inlaid Armor we've been maintaining?","TWN":"我們管理的螺鈿天甲，到底是做什麼的啊？"},"stage":{"bg":"COUNTERSIDE_AURORA_01","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MEMBER2_NPC_SAMGUN_NULL","text":{"KOREA":"하담 군이 삼군문을 세울 적에 만든… 그러니까 그가 전생에 만들었던 발명품이야.","JPN":"カタン君が三軍門を建てる時作った……つまり、彼が前世で作った発明品だ。","ENG":"It's something Ha Dam made when he first founded the Trivanguard… Or more precisely, something he invented in a past life.","TWN":"那是夏垣在建立三軍門時製作的… 也就是他前世的發明品。"},"stage":{"bg":"COUNTERSIDE_AURORA_01","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MEMBER2_NPC_SAMGUN_NULL","text":{"KOREA":"세월을 고개 넘듯 넘나드는 범을 과거에 가두어 놓는 드높은 벽 같은 것이지.","JPN":"丘を越えるように時をも軽く超える虎を、過去に閉じ込めておくための非常に高い壁のようなものだな。","ENG":"Think of it as a massive barrier meant to trap the Tiger in the past as it leaps across time.","TWN":"就像一道高聳的牆，將跨越時間的老虎困在過去。"},"stage":{"bg":"COUNTERSIDE_AURORA_01","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MEMBER2_NPC_SAMGUN_NULL","text":{"KOREA":"그것을 관리하고 보수하는 일은 호혈을 타고난 하담만이 할 수 있어. 자신의 내생까지 염두에 두고 설계한 셈이다.","JPN":"それを管理して補修するのは、虎血を受け継いだカタンにしかできない。そもそも、自分の来世まで念頭に置いて設計していたらしい。","ENG":"And the only one who can maintain and repair it is Ha Dam, someone with Tiger Blood, since it was designed with his future incarnations in mind.","TWN":"只有擁有虎血之人才能管理和修復它。這相當於他考慮到自己的來生而設計的。"},"stage":{"bg":"COUNTERSIDE_AURORA_01","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MEMBER1_NPC_SAMGUN_NULL","text":{"KOREA":"흐음- 범이 현실로 쳐들어오는 걸 막으려면 나전 천갑을 관리해줄 하담을 관리국으로 납치하는 수 밖에 없단 거구나.","JPN":"ふうん……虎が現実に入ってくるのを止めるためには、螺鈿天甲を整備できるカタンを管理局に連れてくるしかなかったってことね。","ENG":"Hmm… So to keep the Tiger from invading our world, their best bet is to drag Ha Dam into the Administration, huh?","TWN":"嗯— 為了阻止老虎侵襲現實，唯一的辦法就是將管理螺鈿天甲的夏垣綁架到管理局。"},"stage":{"bg":"COUNTERSIDE_AURORA_01","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"허나 나전 천갑도 완벽한 대응책은 아니다.","JPN":"しかし、螺鈿天甲とて完璧な対応策ではない。","ENG":"Still, the Heavenly Inlaid Armor isn't a perfect solution.","TWN":"然而螺鈿天甲也不是完美的應對措施。"},"stage":{"bg":"COUNTERSIDE_AURORA_01","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"세상에 위협이 되는 건 세 짐승 뿐만이 아니기에, 다른 커다란 위협이 닥쳐오면 그 여파로 지금의 수가 틀어지고 말 게다.","JPN":"世の脅威となるのは3匹のケモノだけではないからな。別の大きな脅威が押し寄せてくれば、その影響で今の作戦にも誤差が生じてしまうだろう。","ENG":"There are threats beyond the Three Beasts, and if one of them hits hard enough, the entire plan could fall apart.","TWN":"世界上危險的不僅是三隻野獸，如果其他更大的威脅降臨，其餘波會讓現在的局勢出錯。"},"stage":{"bg":"COUNTERSIDE_AURORA_01","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MEMBER1_NPC_SAMGUN_NULL","text":{"KOREA":"그 정도로 큰 위협이라니… 세계 멸망쯤 되는 일이려나요?","JPN":"そうなるほどの大きな脅威って……世界が滅亡するとか？","ENG":"A threat that big…? Are we talking end-of-the-world big?","TWN":"大到那種程度的威脅… 是世界末日之類的嗎？"},"stage":{"bg":"COUNTERSIDE_AURORA_01","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MEMBER2_NPC_SAMGUN_NULL","text":{"KOREA":"하아, 넌 그런 불길한 소릴 아무렇지도 않게 하는구나.","JPN":"はあ、よくもそんな縁起の悪い言葉を口にできるな。","ENG":"*Sigh* You say stuff like that way too casually.","TWN":"唉，你怎麼能毫不在意地說出這麼不吉利的話。"},"stage":{"bg":"COUNTERSIDE_AURORA_01","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MEMBER1_NPC_SAMGUN_NULL","text":{"KOREA":"아무튼, 그때가 오면 명달 대장이 검을 뽑는 걸 볼 수 있는 거네?","JPN":"とにかく、その時になればアカタツ隊長が剣を抜く姿が見れるのね。","ENG":"Well, that just means we might finally see Commander Myeongdal draw his sword, right?","TWN":"總之，等那時候到來，就能看到明達隊長拔劍的樣子囉？"},"stage":{"bg":"COUNTERSIDE_AURORA_01","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MEMBER1_NPC_SAMGUN_NULL","text":{"KOREA":"<color=#ffd34c>이 늙은이는 힘을 아껴두고 있는 게다. 가장 필요한 순간에 쓰기 위해서 말이지</color>라고 그랬으니까.","JPN":"<color=#ffd34c>この年寄りは力を温存しているのだ。最も必要な時に使えるようにな</color>って言ってたから。","ENG":"He said, <color=#ffd34c>\\"This old man is saving his strength. For the moment it matters most.\\"</color>","TWN":"因為他說過<color=#ffd34c>我這老頭只是在保留力量，為的就是要在最需要的瞬間使用</color>。"},"stage":{"bg":"COUNTERSIDE_AURORA_01","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"COUNTERSIDE_AURORA_01","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MEMBER2_NPC_SAMGUN_NULL","text":{"KOREA":"명달 대장님의 피는 윤회가 아닌 불로의 저주. 세 짐승 중 하나인 망량의 것이라 하셨죠.","JPN":"アカタツ隊長の血は、輪廻ではなく不老の呪い。3匹のケモノの1つである魍魎のものだと仰いました。","ENG":"Commander Myeongdal's blood is no ordinary one. It's not reincarnation, but an immortality curse. It's the blood of Mangryang, one of the Three Beasts.","TWN":"明達隊長的血，不是輪迴，而是不老詛咒。據說那是三隻野獸之一的魍魎之血。"},"stage":{"bg":"COUNTERSIDE_AURORA_01","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MEMBER2_NPC_SAMGUN_NULL","text":{"KOREA":"그리고 단 한 번도 그 힘을 후대에 물려준 적이 없었고요.","JPN":"そして一度も、その力を子孫に譲り渡したことはないと。","ENG":"And not once has he ever passed that power down.","TWN":"而且從來沒有將那份力量傳給後代。"},"stage":{"bg":"COUNTERSIDE_AURORA_01","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MEMBER2_NPC_SAMGUN_NULL","text":{"KOREA":"그 오랜 세월, 가족 한 번 만들 생각이 없으셨던 겁니까?","JPN":"長い年月を生きて来て、家族を作ろうとは思わなかったのですか？","ENG":"After all these years, did you really never think about starting a family?","TWN":"這麼多年來，你就沒想過要組織一個家庭嗎？"},"stage":{"bg":"COUNTERSIDE_AURORA_01","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"갑자기 옛날 얘기라도 들려 달라는 게냐? 애들도 아니고.","JPN":"突然昔話が聞きたくなったのか？　子どもでもあるまいし。","ENG":"What, you want me to tell you an old story now? You're not kids.","TWN":"突然要我講老故事嗎？你又不是小孩。"},"stage":{"bg":"COUNTERSIDE_AURORA_01","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"대장에 비하면 저흰 다 애들이죠.","JPN":"隊長に比べたら私たちなんかみんな子どもですよ。","ENG":"Compared to you, we basically are.","TWN":"和隊長比起來，我們都還是小孩啊。"},"stage":{"bg":"COUNTERSIDE_AURORA_01","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"제일삼검 중 한 사람이니, 적어도 수천 살은 잡수신 거잖아요.","JPN":"三剣極の一人ですし、少なくとも数千年は生きてますよね。","ENG":"You're one of the Three Blades. So you've got to be, what, at least a few thousand years old?","TWN":"作為三軍第一劍客之一，你至少也活了幾千年吧。"},"stage":{"bg":"COUNTERSIDE_AURORA_01","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MEMBER1_NPC_SAMGUN_NULL","text":{"KOREA":"왓, 나 처음 알았어. 그럼 대장은 수천 년 동안 솔로였던 거야?","JPN":"わあ、初めて知った。じゃあ、隊長は数千年間独身だったってこと？","ENG":"Whoa, really? That means you've been single for thousands of years, Commander?","TWN":"哇，我第一次知道。那隊長幾千年來都是單身嗎？"},"stage":{"bg":"COUNTERSIDE_AURORA_01","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MEMBER3_NPC_SAMGUN_NULL","text":{"KOREA":"어허, 녀석. 영감님께 말조심하거라.","JPN":"こら、口を慎め。","ENG":"Hey now, show some respect to the elder.","TWN":"嘿，你這小子。對阿姨說話要小心。"},"stage":{"bg":"COUNTERSIDE_AURORA_01","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"…됐다, 됐어.","JPN":"……いいから放っておけ。","ENG":"…It's fine. Let them talk.","TWN":"…算了，算了。"},"stage":{"bg":"COUNTERSIDE_AURORA_01","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"내가 자식 생각이 없고, 딱히 내 자식을 낳아주겠다는 여자도 없었으니. 틀린 말도 아니지.","JPN":"俺は子孫を残す気がなく、かといって俺の子を成してくれる女もいなかったから、あながち間違った表現ではない。","ENG":"They're not wrong. I never felt the urge for children, nor did I ever met anyone who wanted to bear them.","TWN":"我沒有想生孩子，也沒有女人願意為我生孩子。他說的也沒有錯。"},"stage":{"bg":"COUNTERSIDE_AURORA_01","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MEMBER1_NPC_SAMGUN_NULL","text":{"KOREA":"연애에 자식이 중요한가? 애를 안 낳아도 여자는 얼마든지 사귀면 되잖아.","JPN":"恋愛と子どもは別でしょう？　子どもを生まなくても、女性とつき合うだけならいくらでもできるじゃない。","ENG":"Who says you need kids to date someone? You can still have a girlfriend without having kids.","TWN":"戀愛中孩子很重要嗎？就算不生孩子，也可以交女朋友啊。"},"stage":{"bg":"COUNTERSIDE_AURORA_01","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"허허, 나처럼 고리타분한 옛 사람에게 혼사는 자손을 두는 것이 전제이거늘.","JPN":"はは、俺のような古い人間にとって、婚姻とは子を生むことを前提としている。","ENG":"Heh, for an old-timer like me, marriage is supposed to mean leaving behind a lineage.","TWN":"呵呵，像我這種守舊的老人，結婚是以傳宗接代為前提的。"},"stage":{"bg":"COUNTERSIDE_AURORA_01","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};